const text = $json.output;

// Extract only number
const match = text.match(/\d+/);

return [
  {
    json: {
      product_code: match ? match[0] : null
    }
  }
];

// Access full response (make sure "Full Response" is enabled in HTTP node)
const headers = $json.headers;

// 🔐 Extract CSRF Token
const csrf_token = headers['x-csrf-token'];

// 🍪 Extract Cookies safely
let cookies = headers['set-cookie'];

if (Array.isArray(cookies)) {
  cookies = cookies
    .map(c => c.split(';')[0])   // keep only key=value
    .join('; ');
} else if (typeof cookies === 'string') {
  cookies = cookies.split(';')[0];
}

// ✅ Return structured output
return [
  {
    json: {
      csrf_token,
      cookie: cookies
    }
  }
];

